SELECT type_name
FROM plant_types
WHERE average_efficiency = (SELECT MAX(average_efficiency) FROM plant_types);

SELECT status
FROM plant_status
WHERE plant_id = 12875 AND timestamp = '2023-05-01 08:00:00';

SELECT COUNT(*) AS status_count
FROM plant_status
WHERE plant_id = 12875;

SELECT SUM(capacity) AS total_capacity
FROM bus_aggregations
WHERE region = 'California';

SELECT COUNT(*) AS bus_aggregation_count
FROM bus_aggregations
WHERE region = 'North';

SELECT plant_id, mu_Pmax, AVG(seasonal_adjustment) AS avg_seasonal_adjustment
FROM plant_cost_coefficients
GROUP BY plant_id, mu_Pmax;

SELECT plant_id, Pmax, Pmin
FROM plant_operational_params
WHERE Pmax > 200;

SELECT location, capacity
FROM interconnections
WHERE capacity > 1000;

SELECT SUM(capacity) AS total_capacity
FROM bus_aggregations
WHERE region = 'Region B';

SELECT plant_id, maintenance_cost
FROM plant_cost_params
WHERE maintenance_cost > 40000;

SELECT MAX(capacity) AS max_capacity
FROM bus_aggregations
WHERE region = 'Texas';

SELECT interconnect_id, location, description, capacity
FROM interconnections
ORDER BY capacity DESC;

SELECT type_id, type_name, average_lifespan, average_efficiency
FROM plant_types
WHERE type_name = 'wind';
